var e=[{id:`L2_1`,type:`dialog`,speaker:`BELL_DANMACHI_NULL_NULL`,text:{KOREA:`설령 압도적인 부조리함이 막아서더라도 더는 포기하지 않아요.`,JPN:`たとえ圧倒的な不条理が僕を止めるとしても、諦めません。`,ENG:`Even if the overwhelming odds are against me, I won't give up.`,TWN:`Even if the overwhelming odds are against me, I won't give up.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BELL_DANMACHI_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`BELL_DANMACHI_NULL_NULL`,text:{KOREA:`모험을 계속해 나가다 보면, 언젠가 목표로 하는 이상에 다다를 수 있을 테니까요.`,JPN:`冒険を続けていくと、いつか理想にたどり着けるはずですから。`,ENG:`If I keep adventuring, one day I'll reach my goal.`,TWN:`If I keep adventuring, one day I'll reach my goal.`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`BELL_DANMACHI_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};